package com.example.news.aggregation.agent.domain;import com.example.news.aggregation.agent.enums.ConversationState;import com.fasterxml.jackson.annotation.JsonIgnoreProperties;import lombok.AllArgsConstructor;import lombok.Builder;import lombok.Data;import lombok.NoArgsConstructor;import java.io.Serializable;import java.time.LocalDateTime;import java.util.ArrayList;import java.util.List;/** * 会话状态 * 存储用户对话的完整上下文，持久化到Redis */@Data@Builder@NoArgsConstructor@AllArgsConstructor@JsonIgnoreProperties(ignoreUnknown = true)public class SessionState implements Serializable {    private static final long serialVersionUID = 1L;        /**     * 会话ID     */    private String sessionId;        /**     * 用户ID     */    private String userId;        /**     * 当前对话状态     */    @Builder.Default    private ConversationState conversationState = ConversationState.NEED_SCOPE;        /**     * 用户约束条件     */    private Constraints constraints;        /**     * 对话历史 (用户query + Agent回复)     */    @Builder.Default    private List<String> history = new ArrayList<>();        /**     * 当前候选文章ID列表     */    @Builder.Default    private List<Long> currentCandidates = new ArrayList<>();        /**     * 检索尝试记录     */    @Builder.Default    private List<RetrievalAttempt> attempts = new ArrayList<>();        /**     * 剩余预算 (限制LLM调用次数)     */    @Builder.Default    private Integer budget = 10;        /**     * 会话创建时间     */    private LocalDateTime createdAt;        /**     * 最后更新时间     */    private LocalDateTime updatedAt;        /**     * 添加对话历史     */    public void addHistory(String message) {        if (history == null) {            history = new ArrayList<>();        }        history.add(message);        this.updatedAt = LocalDateTime.now();    }        /**     * 添加检索尝试     */    public void addAttempt(RetrievalAttempt attempt) {        if (attempts == null) {            attempts = new ArrayList<>();        }        attempts.add(attempt);        this.updatedAt = LocalDateTime.now();    }        /**     * 更新候选文章     */    public void updateCandidates(List<Long> articleIds) {        this.currentCandidates = articleIds;        this.updatedAt = LocalDateTime.now();    }        /**     * 消耗预算     */    public void consumeBudget(int amount) {        this.budget = Math.max(0, this.budget - amount);        this.updatedAt = LocalDateTime.now();    }        /**     * 检查预算是否耗尽     */    public boolean isBudgetExhausted() {        return budget != null && budget <= 0;    }}